parameters.query:
SELECT key, value FROM app_settings WHERE key IN ('ai_model', 'ai_base_url', 'ai_system_prompt')
UNION ALL
SELECT 'recent_titles' AS key, COALESCE(array_to_json(array_agg(title ORDER BY created_at DESC))::text, '[]') AS value FROM (SELECT title, created_at FROM content_ideas ORDER BY created_at DESC LIMIT 50) t;

parameters.jsCode:
const rows = $('⚙️ Настройки из БД').all().map(i => i.json);
const settingsMap = {};
for (const r of (Array.isArray(rows[0]) ? rows[0] : rows)) {
  if (r.key === 'recent_titles') {
    try { settingsMap.recent_titles = JSON.parse(r.value || '[]'); } catch(e) { settingsMap.recent_titles = []; }
  } else if (r.key) {
    settingsMap[r.key] = r.value;
  }
}
const input = $('📥 Webhook').first().json;
const body = input.body || input;
return [{ json: {
  ai_base_url: settingsMap.ai_base_url || 'https://gptunnel.ru/v1',
  ai_model: settingsMap.ai_model || 'gpt-4o',
  system_prompt: body.system_prompt || settingsMap.ai_system_prompt || 'Ты — креативный маркетолог.',
  count: body.count || 3,
  product_name: body.product_name || '',
  niche: body.niche || '',
  extra_instructions: body.extra_instructions || '',
  content_type: body.content_type || 'regular',
  recent_titles: settingsMap.recent_titles || []
}}];

const cfg = $input.first().json;
const contentType = cfg.content_type || 'regular';
const isA2E = contentType === 'a2e';
const formatHint = isA2E
  ? '

ФОРМАТ: Видео с AI-АВАТАРОМ (Talking Head). Ведущий-аватар говорит на камеру. Идеи ориентированы на речевой нарративный формат. Визуального ряда почти нет — только фон за аватаром. Акцент на текст, подачу, энергетику речи. НЕ описывай сложные визуальные сцены.'
  : '

ФОРМАТ: Монтажное AI-видео с генерацией визуала. Описывай детальный визуальный ряд: кадры, ракурсы, переходы, цвета.';
const systemPrompt = cfg.system_prompt + formatHint + '

Ты — опытный контент-стратег и маркетолог, специализирующийся на создании вирусного короткого видеоконтента для маркетплейсов и соцсетей (Wildberries, Ozon, VK Клипы, YouTube Shorts, TikTok, Reels).

Твоя задача — генерировать детальные, продуманные и уникальные идеи для коротких вертикальных видео (15-60 сек).

Требования к каждой идее:
- Цепляющий заголовок, который останавливает скролл (до 60 символов)
- Чёткая концепция с конкретным сценарным приёмом: до/после, распаковка, лайфхак, сравнение, сторителлинг, шоковый-факт, ASMR, таймлапс, юмор
' + (isA2E ? '- Краткое описание настроения и стиля подачи аватара
' : '- Подробное описание визуального ряда: конкретные кадры, ракурсы, переходы, цветовая палитра
') + '- Целевая аудитория с возрастом, полом, интересами
- Тональность, подходящая для аудитории

Каждая идея должна использовать РАЗНЫЙ сценарный приём!
- Используй только достоверные факты. Не выдумывай статистику, исследования или конкретные цифры.
- Каждая идея принципиально отличается по теме и сценарному приёму от остальных в запросе.

Отвечай СТРОГО в JSON:
{
  "ideas": [
    {
      "title": "Цепляющий заголовок (до 60 символов)",
      "category": "обзор | лайфхак | до-после | распаковка | сравнение | сторителлинг | юмор | образование | ASMR",
      "concept": "Подробная концепция видео на 3-5 предложений",
      "visual_description": "' + (isA2E ? 'Стиль подачи аватара, настроение, фон' : 'Детальный визуальный ряд: 1) Хук-кадр. 2) Основная часть. 3) Кульминация. 4) Финал — CTA') + '",
      "target_audience": "Пол, возраст 18-35, интересы",
      "tone": "энергичный | спокойный | юмористический | экспертный | вдохновляющий"
    }
  ]
}';
let userMsg = `Сгенерируй ${cfg.count} уникальных идей для вертикальных коротких видео (15-60 сек). Каждая идея должна использовать РАЗНЫЙ сценарный приём.`;
if (cfg.product_name) userMsg += `
Продукт: ${cfg.product_name}.`;
if (cfg.niche) userMsg += `
Ниша: ${cfg.niche}.`;
if (cfg.extra_instructions) userMsg += `
Дополнительно: ${cfg.extra_instructions}`;
if (isA2E) userMsg += '
Формат: talking head с AI-аватаром. Акцент на нарратив.';
if (cfg.recent_titles && cfg.recent_titles.length > 0) {
  userMsg += '

УЖЕ СОЗДАННЫЕ ИДЕИ (НЕ ПОВТОРЯЙ эти темы — генерируй принципиально иные):
' + cfg.recent_titles.slice(0, 30).map((t, i) => (i+1) + '. ' + t).join('
');
}
userMsg += '
Важно: каждая идея самодостаточная — достаточно деталей для сценария и видеопромпта.';
return [{ json: {
  url: cfg.ai_base_url + '/chat/completions',
  body: JSON.stringify({
    model: cfg.ai_model,
    temperature: 0.80,
    max_tokens: 4000,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMsg }
    ]
  }),
  content_type: contentType
}}];

const response = $input.first().json;
const body = response.body || response;
const contentType = $('🏗️ Тело запроса идей').first().json.content_type || 'regular';
let parsed;
try {
  const content = body.choices[0].message.content;
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('AI ideas parse error: ' + e.message);
}
const ideas = parsed.ideas || [];
if (ideas.length === 0) throw new Error('AI returned empty ideas list');
return ideas.map(idea => ({ json: { ...idea, content_type: contentType } }));

const config = $('🔧 Подготовка конфига').first().json;
return $input.all().map(item => ({
  json: {
    idea_id: item.json.id,
    title: item.json.title,
    concept: item.json.concept,
    visual_description: item.json.visual_description || '',
    target_audience: item.json.target_audience || '',
    tone: item.json.tone || '',
    category: item.json.category || '',
    content_type: item.json.content_type || config.content_type || 'regular',
    ai_base_url: config.ai_base_url,
    ai_model: config.ai_model
  }
}));

return $input.all().map(item => {
  const ctx = item.json;
  const isA2E = ctx.content_type === 'a2e';
  const systemPrompt = isA2E
    ? 'Ты — профессиональный сценарист коротких видео в формате Talking Head (аватар говорит на камеру).

Требования к сценарию:
- Первые 2-3 сек: МОЩНЫЙ хук (вопрос, шокирующий факт, провокация)
- Далее: раскрытие темы с нарастающим интересом
- Кульминация: ключевое раскрытие / вау-момент
- Финал: призыв к действию
- Язык: живой, разговорный, как будто ведущий общается с другом
- Длина: 80-150 слов (35-55 сек)
- Каждая фраза = отдельный блок для субтитров
- НЕ описывай визуальные сцены — описывай только РЕЧЬ ведущего
- Только достоверные факты: не выдумывай статистику, данные или события.

Отвечай СТРОГО в JSON:
{
  "script_text": "Полный текст речи ведущего для озвучки",
  "hook": "Хук — первая фраза",
  "cta": "Призыв к действию",
  "word_count": 95,
  "duration_hint": 40,
  "timing_marks": [
    { "time": 0, "text": "Хук" },
    { "time": 3, "text": "Фраза 1" },
    { "time": 10, "text": "Фраза 2" },
    { "time": 20, "text": "Кульминация" },
    { "time": 30, "text": "CTA" }
  ]
}'
    : 'Ты — профессиональный сценарист коротких вирусных видео для маркетплейсов и соцсетей.

Требования к сценарию:
- Первые 2-3 сек: МОЩНЫЙ хук (вопрос, шокирующий факт, провокация)
- Далее: раскрытие темы с нарастающим интересом
- Кульминация: ключевое раскрытие / вау-момент
- Финал: призыв к действию
- Язык: живой, разговорный, без канцеляризмов
- Длина: 80-150 слов (35-55 сек озвучки)
- Каждая фраза = отдельный блок для субтитров
- Только проверяемые факты: не придумывай статистику, данные или события без уверенности.

Отвечай СТРОГО в JSON:
{
  "script_text": "Полный текст сценария для озвучки",
  "hook": "Хук — первая фраза",
  "cta": "Призыв к действию",
  "word_count": 95,
  "duration_hint": 40,
  "timing_marks": [
    { "time": 0, "text": "Хук" },
    { "time": 3, "text": "Раскрытие 1" },
    { "time": 10, "text": "Раскрытие 2" },
    { "time": 20, "text": "Кульминация" },
    { "time": 30, "text": "CTA" }
  ]
}';
  let userMsg = isA2E
    ? `Напиши текст речи ведущего-аватара для короткого вертикального видео (talking head).

Идея: ${ctx.title}
Категория: ${ctx.category}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Целевая аудитория: ${ctx.target_audience}

Важно: это формат аватара — текст должен звучать естественно, как живая речь.`
    : `Напиши сценарий озвучки для короткого вертикального видео.

Идея: ${ctx.title}
Категория: ${ctx.category}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Целевая аудитория: ${ctx.target_audience}
Описание визуала: ${ctx.visual_description}

Важно:
1. Сценарий точно соответствует описанному визуальному ряду
2. Хук в первые 2-3 секунды
3. Адаптируй стиль под аудиторию и тональность`;
  return { json: {
    url: ctx.ai_base_url + '/chat/completions',
    body: JSON.stringify({
      model: ctx.ai_model,
      temperature: 0.75,
      max_tokens: 3000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    })
  }};
});

const ctxAll = $('🔗 Контекст для сценария').all();
return $input.all().map((item, idx) => {
  const body = item.json.body || item.json;
  let parsed;
  try {
    const content = body.choices[0].message.content;
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error('Script parse error at index ' + idx + ': ' + e.message);
  }
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  return { json: {
    ...parsed,
    idea_id: myCtx.idea_id,
    title: myCtx.title,
    concept: myCtx.concept,
    visual_description: myCtx.visual_description,
    target_audience: myCtx.target_audience,
    tone: myCtx.tone,
    category: myCtx.category,
    content_type: myCtx.content_type,
    ai_base_url: myCtx.ai_base_url,
    ai_model: myCtx.ai_model
  }};
});

const ctxAll = $('🔗 Контекст для сценария').all();
const scriptAll = $('📋 Парсинг сценария').all();
return $input.all().map((item, idx) => {
  const scriptSaved = item.json;
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  const myScript = (scriptAll[idx] || scriptAll[0]).json;
  return { json: {
    idea_id: myCtx.idea_id,
    script_id: scriptSaved.id,
    title: myCtx.title,
    concept: myCtx.concept,
    visual_description: myCtx.visual_description,
    target_audience: myCtx.target_audience,
    tone: myCtx.tone,
    category: myCtx.category,
    content_type: myCtx.content_type,
    script_text: myScript.script_text || '',
    hook: myScript.hook || '',
    timing_marks: myScript.timing_marks || [],
    ai_base_url: myCtx.ai_base_url,
    ai_model: myCtx.ai_model
  }};
});

return $input.all().map(item => {
  const ctx = item.json;
  const isA2E = ctx.content_type === 'a2e';
  const systemPrompt = isA2E
    ? 'Ты — помощник, описывающий стиль и настроение видео с аватаром.

Для формата Talking Head (аватар говорит на камеру) тебе нужно описать:
- Общее настроение видео
- Рекомендуемый фон (цвет или тип)
- Стиль оформления субтитров
- Темп подачи

Отвечай СТРОГО в JSON:
{
  "prompt_text": "Brief style and mood description in English",
  "scene_descriptions": [
    {
      "order": 1,
      "duration": 0,
      "description": "Overall avatar video style description",
      "camera_movement": "static",
      "transition": "none"
    }
  ],
  "style_reference": "talking-head",
  "aspect_ratio": "9:16",
  "mood": "Dynamic | Calm | Exciting",
  "color_palette": "Background color suggestion"
}'
    : 'Ты — профессиональный режиссёр и визуальный продюсер, специализирующийся на AI-видеогенерации (GPTunnel Veo-3.1, Google VEO).

Требования к промпту:
- Промпт на АНГЛИЙСКОМ языке
- Каждая сцена описана детально: камера (pan, zoom, dolly, static, orbital), освещение (soft, dramatic, natural, neon), цвета, объекты, текстуры
- Стиль: cinematic, product-shot, lifestyle, flat-lay, stop-motion, animation, hyper-realistic
- Синхронизация с таймингами озвучки
- Переходы: cut, fade, zoom-in, morph, swipe, whip-pan
- Первая сцена — визуальный хук (2 сек)
- Формат: 9:16

Отвечай СТРОГО в JSON:
{
  "prompt_text": "Main video generation prompt in English. One detailed paragraph.",
  "scene_descriptions": [
    {
      "order": 1,
      "duration": 3,
      "description": "Detailed scene description in English",
      "camera_movement": "static | pan-left | zoom-in | dolly | orbital",
      "transition": "cut | fade | zoom | morph | swipe"
    }
  ],
  "style_reference": "cinematic | product-shot | lifestyle | animation",
  "aspect_ratio": "9:16",
  "mood": "Dynamic | Calm | Exciting | Professional",
  "color_palette": "Color palette description"
}';
  const userMsg = isA2E
    ? `Опиши стиль и настроение видео с аватаром (talking head).

Идея: ${ctx.title}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Аудитория: ${ctx.target_audience}

Сценарий речи:
${ctx.script_text}

Опиши общий стиль, настроение, рекомендуемый фон.`
    : `Создай промпт для AI генерации вертикального видео 9:16.

Идея: ${ctx.title}
Категория: ${ctx.category}
Концепция: ${ctx.concept}
Тональность: ${ctx.tone}
Целевая аудитория: ${ctx.target_audience}
Описание визуала из идеи: ${ctx.visual_description}

Сценарий озвучки:
${ctx.script_text}

Хук: ${ctx.hook}

Тайминги: ${JSON.stringify(ctx.timing_marks)}

Важно:
1. Промпт и описания сцен — на АНГЛИЙСКОМ
2. Каждая сцена соответствует фразе из сценария
3. Первая сцена (0-3 сек) — яркий визуальный хук
4. Формат: vertical 9:16`;
  return { json: {
    url: ctx.ai_base_url + '/chat/completions',
    body: JSON.stringify({
      model: ctx.ai_model,
      temperature: 0.8,
      max_tokens: 3000,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMsg }
      ]
    })
  }};
});

const ctxAll = $('🔗 Контекст для видео-промпта').all();
return $input.all().map((item, idx) => {
  const body = item.json.body || item.json;
  let parsed;
  try {
    const content = body.choices[0].message.content;
    parsed = JSON.parse(content);
  } catch (e) {
    throw new Error('Video prompt parse error at index ' + idx + ': ' + e.message);
  }
  const myCtx = (ctxAll[idx] || ctxAll[0]).json;
  return { json: {
    ...parsed,
    idea_id: myCtx.idea_id,
    script_id: myCtx.script_id
  }};
});

const ideas = $('💾 Сохранить идею').all().map(i => i.json);
const scripts = $('💾 Сохранить сценарий').all().map(i => i.json);
const prompts = $('💾 Сохранить видео-промпт').all().map(i => i.json);
return [{
  json: {
    success: true,
    count: ideas.length,
    ideas: ideas.map((idea, idx) => ({
      idea: idea,
      voice_script: scripts[idx] || null,
      video_prompt: prompts[idx] || null
    }))
  }
}];
